UPDATE `product_order` SET
status = #{data.status}, pay_time = #{data.payTime}, up_order_no = #{data.upOrderNo}, express_company_name = #{data.expressCompanyName}, express_company_code = #{data.expressCompanyCode}, express_no = #{data.expressNo}, express_status = #{data.expressStatus}, refund_amount = #{data.refundAmount}, refund_time = #{data.refundTime}, refund_remark = #{data.refundRemark}, remark = #{data.remark}, divide_status = #{data.divideStatus}, divide_amount = #{data.divideAmount}, divide_time = #{data.divideTime},
WHERE id = #{data.id}

