SELECT *
FROM `product_order`

    AND user_id = #{param.searchField1}
    AND product_id = #{param.searchField2}

        AND `status` IN

            #{item}


    AND `status` = #{param.searchIntStatus}
    AND `express_status` = #{param.searchField3}
    AND `shop_id` = #{param.searchField4}

        AND `order_no` LIKE CONCAT('%', #{param.searchStrField1}, '%')


        AND `product_name` LIKE CONCAT('%', #{param.searchStrField2}, '%')


        AND `serial_number` LIKE CONCAT('%', #{param.searchStrField3}, '%')


        AND (phone LIKE CONCAT('%',#{param.keyword},'%') OR nick_name LIKE CONCAT('%',#{param.keyword},'%'))


        AND `create_time` BETWEEN #{param.startTime} AND #{param.endTime}


ORDER BY `id` desc

